css:
.loader {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      gap: 5px;
      min-width: 64px;
      min-height: 22px;
    }
    .loader i {
      display: block;
      width: 11px;
      height: 11px;
      border-radius: 50%;
      background: var(--loader-color);
      animation: dotPulse 0.95s ease-in-out infinite;
    }
    .loader i:nth-child(1) { animation-delay: 0.00s; }
.loader i:nth-child(2) { animation-delay: 0.12s; }
.loader i:nth-child(3) { animation-delay: 0.24s; }
.loader i:nth-child(4) { animation-delay: 0.36s; }
    @keyframes dotPulse { 0%, 100% { transform: translateY(0); opacity: .45; } 45% { transform: translateY(-12px); opacity: 1; } }
